<template>
    <div class="img1" :style="{background: 'url(' + bg + ')'}"> 
        <!-- <input v-model="lifeValue" type="password" @keyup.enter="toLife">
        <button type="button" class="btn btn-primary" @click="toLife">生活</button>
        <button type="button" class="btn btn-primary" @click="toBrowser">图集</button>
        <button type="button" class="btn btn-primary" @click="toBrowser">职业</button>
        <button type="button" class="btn btn-primary" @click="toBrowser">学习</button>
        <button type="button" class="btn btn-primary" @click="toBrowser">兴趣</button>
        <button type="button" class="btn btn-primary" @click="toBrowser">城市</button>

        animation:rev 10s linear infinite;
        transition:all .5s;
        <img src="../assets/images/1.jpg" style="width:100%;">
        <button type="button" class="btn btn-primary" @click="toBrowser">资源</button> -->
        <div :style="{background: 'url(' + bg + ')' }" class="vertical main">
            <button type="button" class="btn btn-primary vertical" @click="toLife">生活</button>
            <button type="button" class="btn btn-primary photos" @click="toLife">图集</button>
            <button type="button" class="btn btn-primary source" @click="toLife">资源</button>
            <button type="button" class="btn btn-primary profession" @click="toLife">职业</button>
            <button type="button" class="btn btn-primary learn" @click="toLife">学习</button>
            <button type="button" class="btn btn-primary hobby" @click="toLife">兴趣</button>
            <button type="button" class="btn btn-primary city" @click="toLife">城市</button>
            
        </div>
    </div>
</template>
<script>
    import BG from '../assets/images/background.jpg';
export default {
    data(){
        return{
            lifeValue:"7777",
            bg:BG,
        }
    },
    methods:{
        toLife(){
            if(this.lifeValue=="7777"){
                this.$router.push('/life');
            }else{
                alert("密码错误");
            };
        },
        toBrowser(){
            this.$router.push('/life');
        },
    }
}

</script>
<style scoped>
    .vertical{
        position: absolute;
        top:50%;
        left:50%;
        transform:translate(-50%, -50%);
        
    }
    .photos{
        position: absolute;
        top:0%;
        left:50%;
        transform:translate(-50%, -50%);
    }
    .source{
        position: absolute;
        top:100%;
        left:50%;
        transform:translate(-50%, -50%);
    }
    .profession{
        position: absolute;
        top:25%;
        left:5%;
        transform:translate(-50%, -50%);
    }
    .learn{
        position: relative;
        top:25%;
        left:93%;
        transform:translate(-50%, -50%);
    }
    .hobby{
        position: absolute;
        top:75%;
        left:5%;
        transform:translate(-50%, -50%);
    }
    .city{
        position: relative;
        top:75%;
        left:80%;
        transform:translate(-50%, -50%);
    }
    .main{
        height:520px;
        width:520px;
        border:1px solid red;
        border-radius: 50%;
    }
    @keyframes rev{
        0%{background: red}
        25%{background: yellow}
        75%{background: blue}
        100%{background:red}
    }
    .img1{
        height:700px;
    }
</style>



