import Vue from 'vue'
import Router from 'vue-router'

Vue.use(Router)

export default new Router({
  routes: [
    {
      path: '/',
      name: 'index',
      component: require('@/components/index').default
    },
    {
      path: '*',
      name: '404',
      component: require('@/components/index').default
    },
    {
      path: '/life',
      name: 'life',
      component: require('@/components/life/life').default,
      redirect:"/home",
      children:[
        {
          path: '/home',
          name: 'home',
          component: require('@/components/life/home').default
        },
        {
          path: '/photos',
          name: 'photos',
          component: require('@/components/life/photos').default,
          redirect:"/plant",
          children:[
            {
              path: '/plant',
              name: 'plant',
              component: require('@/components/life/photos/plant').default
            },
            {
              path: '/animal',
              name: 'animal',
              component: require('@/components/life/photos/animal').default
            },
            {
              path: '/travel',
              name: 'travel',
              component: require('@/components/life/photos/travel').default
            },
          ]
        },
        {
          path: '/skill',
          name: 'skill',
          component: require('@/components/life/skill').default,
          redirect:"/mechanical",
          children:[
            {
              path: '/mechanical',
              name: 'mechanical',
              component: require('@/components/life/skill/mechanical').default
            },
            {
              path: '/computer',
              name: 'computer',
              component: require('@/components/life/skill/computer').default
            },
            {
              path: '/web',
              name: 'web',
              component: require('@/components/life/skill/web').default
            },
            {
              path: '/project',
              name: 'project',
              component: require('@/components/life/skill/project').default
            },
          ]
        },
        {
          path: '/interests',
          name: 'interests',
          component: require('@/components/life/interests').default,
          redirect:"/epub",
          children:[
            {
              path: '/epub',
              name: 'epub',
              component: require('@/components/life/interests/epub').default
            },
            {
              path: '/movie',
              name: 'movie',
              component: require('@/components/life/interests/movie').default
            },
            {
              path: '/financial',
              name: 'financial',
              component: require('@/components/life/interests/financial').default
            },
            {
              path: '/game',
              name: 'game',
              component: require('@/components/life/interests/game').default
            },
          ]
        },
      ],
    },
    {
      path: '/browser',
      name: 'browser',
      component: require('@/components/browser/browser').default,
      redirect:"/runoob",
      children:[
        {
          path: '/runoob',
          name: 'runoob',
          component: require('@/components/browser/runoob').default,

        }
      ]
    },
    
  ]
})



